require "config.BlockConfig"

Area = class()

function Area:ctor(center, range, withPos)
    if withPos ~= nil then
        self:initAreaWithPos(center, range)
        return
    end
    self.center = center
    self.range = range
    self:initArea(self.range)
end

function Area:initAreaWithPos(startPos, endPos)
    self.startPos = startPos
    self.endPos = endPos
    self.minX = self.startPos.x
    self.maxX = self.endPos.x
    self.minY = self.startPos.y
    self.maxY = self.endPos.y
    self.minZ = self.startPos.z
    self.maxZ = self.endPos.z
end

function Area:resetArea(position, range)
    self.center = position
    self.range = range or self.range
    self:initArea(self.range)
end

function Area:initArea(range)
    self.minX = self.center.x - range
    self.maxX = self.center.x + range
    self.minY = self.center.y - range - 0.5
    self.maxY = self.center.y + range + 0.5
    self.minZ = self.center.z - range
    self.maxZ = self.center.z + range
end

function Area:isInArea(pos)
    return pos.x >= self.minX and pos.x <= self.maxX
            and pos.y >= self.minY and pos.y <= self.maxY
            and pos.z >= self.minZ and pos.z <= self.maxZ
end

function Area:setBloodReturn(health, appleDuration)
    local bloodValue = StringUtil.split(health, "#")
    self.apple = tonumber(bloodValue[1])
    self.health = tonumber(bloodValue[2])
    self.appleDuration = appleDuration
end

function Area:getBloodReturn()
    return self.apple, self.health, self.appleDuration
end

function Area:setIceTime(time)
    self.iceTime = time
end

function Area:changeBlockToIce(blockId, position, userId)
    EngineWorld:setBlock(position, BlockID.PACKED_ICE)
    LuaTimer:schedule(function(userId)
        local player = PlayerManager:getPlayerByUserId(userId)
        local meta = EngineWorld:getBlockMeta(position)
        if not player then
            EngineWorld:setBlock(position, blockId, meta)
            return
        end
        local newPos = player:getPosition()
        if math.abs(newPos.x - position.x) < self.range + 1 and
                math.abs(newPos.y - position.y) <= 1 and
                math.abs(newPos.z - position.z) < self.range + 1 then
            self:changeBlockToIce(blockId, position, userId)
            return
        end
        local newId = EngineWorld:getBlockId(position)
        if newId ~= BlockID.PACKED_ICE then
            self:changeBlockToIce(blockId, position, userId)
            return
        end
        EngineWorld:setBlock(position, blockId, meta)
    end, self.iceTime * 1000, nil, userId)
end

function Area:changeIce(player, pos)
    for i = pos.x - self.range, pos.x + self.range do
        for j = pos.z - self.range, pos.z + self.range do
            local position = VectorUtil.toBlockVector3(i, pos.y - 1, j)
            local blockId = EngineWorld:getBlockId(position)
            if self:canBeIce(blockId) then
                self:changeBlockToIce(blockId, position, player.userId)
            end
        end
    end
end

function Area:canBeIce(blockId)
    return blockId ~= BlockID.PACKED_ICE
            and blockId ~= BlockID.LADDER
            and blockId ~= BlockID.AIR
            and blockId ~= BlockID.CHEST
            and not (TableUtil.include(BlockConfig.BlockId, blockId))
end

function Area:getBlockInArea()
    local result = {}
    for i = self.center.x - self.range, self.center.x + self.range do
        for j = self.center.z - self.range, self.center.z + self.range do
            for q = self.center.y - self.range, self.center.y + self.range do
                local position = VectorUtil.newVector3i(i, q, j)
                local blockId = EngineWorld:getBlockId(position)
                if blockId ~= BlockID.AIR and blockId ~= BlockID.CHEST then
                    table.insert(result, {
                        hash = VectorUtil.hashVector3(position),
                        pos = position
                    })
                end
            end
        end
    end
    return result
end

function Area:getPlayerInArea()
    local result = {}
    local players = PlayerManager:copyPlayers()
    for _, player in pairs(players) do
        if not player:ifOnMount() and player.isLife == true and self:isInArea(player:getPosition()) then
            table.insert(result, {
                pos = player:getPosition(),
                userId = player.userId
            })
        end
    end
    return result
end

return Area